","new_string":"    private fun ASTNode.findNodeAfterTrailingCommaPosition(): ASTNode {
        val lastEnumEntry = children().last { it.psi is KtEnumEntry }

        // Depending on how the enum is written (and parsed), the semicolon which terminates the enum entries can be a
        // child of the last enum entry or a direct sibling in the class body.
        val semicolonAfterLastEnumEntry =
            lastEnumEntry
                .children()
                .singleOrNull { it.elementType == ElementType.SEMICOLON }
                ?: run {
                    var leaf = lastEnumEntry.psi.nextLeaf(skipEmptyElements = false)
                    while (leaf is PsiWhiteSpace) {
                        leaf = leaf.nextLeaf(skipEmptyElements = false)
                    }
                    leaf?.node?.takeIf { it.elementType == ElementType.SEMICOLON }
                }

        return semicolonAfterLastEnumEntry ?: lastChildNode
    }
