{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/TrailingCommaOnDeclarationSiteRuleEnumWithCompanionObjectRegressionTest.kt","content":"package com.pinterest.ktlint.ruleset.standard

import com.pinterest.ktlint.core.KtLintRuleEngine
import com.pinterest.ktlint.core.LintError
import com.pinterest.ktlint.core.RuleProvider
import com.pinterest.ktlint.core.api.EditorConfigOverride
import com.pinterest.ktlint.ruleset.standard.TrailingCommaOnDeclarationSiteRule.Companion.TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test

class TrailingCommaOnDeclarationSiteRuleEnumWithCompanionObjectRegressionTest {
    @Test
    fun `Given enum entries followed by companion object then formatting adds trailing comma without leaving violations`() {
        val code =
            """
            enum class TestEnum() {
                A,
                B;

                companion object {
                    const val A_NUMBER = 1L
                }
            }
            """.trimIndent()

        val formattedCode =
            """
            enum class TestEnum() {
                A,
                B,
                ;

                companion object {
                    const val A_NUMBER = 1L
                }
            }
            """.trimIndent()

        val ruleEngine =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { TrailingCommaOnDeclarationSiteRule() },
                        RuleProvider { WrappingRule() },
                        RuleProvider { NoSemicolonsRule() },
                    ),
                editorConfigOverride = EditorConfigOverride.from(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true),
            )

        val uncorrectedErrors = mutableListOf<LintError>()
        val actualFormattedCode =
            ruleEngine.format(code) { lintError, corrected ->
                if (!corrected) {
                    uncorrectedErrors.add(lintError)
                }
            }

        assertThat(uncorrectedErrors).isEmpty()
        assertThat(actualFormattedCode).isEqualTo(formattedCode)

        val lintErrors = mutableListOf<LintError>()
        ruleEngine.lint(actualFormattedCode) { lintErrors.add(it) }
        assertThat(lintErrors).isEmpty()
    }
}
"}

